cimal(14,4)) else cast((((((((((coalesce(`p`.`prod_total_units`,0)) - coalesce(`p`.`loss_uncapped_units`,0)) - cast((coalesce(`p`.`loss_half_filled_units`,0) * 0.5) as decimal(14,6))) - coalesce(`p`.`loss_untaxed_full_units`,0)) - coalesce(`p`.`qa_library_units`,0)) - coalesce(`p`.`qa_analyses_units`,0)) / `s`.`units_per_pack`) * `s`.`hl_per_unit`) - (coalesce(`p`.`loss_liquid_other_units`,0) / 100)) as decimal(14,4)) end) AS `beer_tax_base_hl`,(case when (`p`.`reuses_packaging_id_fk` is not null) then 0 when ((`s`.`hl_per_unit` is null) or (`s`.`units_per_pack` is null) or (`s`.`units_per_pack` <= 0)) then NULL when (`p`.`run_type` in ('keg','cuv')) then cast((coalesce(`p`.`loss_keg_liquid_l`,0) / 100) as decimal(14,4)) else cast((((((coalesce(`p`.`unsaleable_units`,0) + coalesce(`p`.`loss_uncapped_units`,0)) + cast((coalesce(`p`.`loss_half_filled_units`,0) * 0.5) as decimal(14,6))) + coalesce(`p`.`loss_untaxed_full_units`,0)) / `s`.`units_per_pack`) * `s`.`hl_per_unit`) as decimal(14,4)) end) AS `loss_kpi_hl` from (`bd_packaging_v2` `p` left join `ref_skus` `s` on((`s`.`id` = `p`.`sku_id_fk`)));
